#include <bits/stdc++.h>
using namespace std;
const int N=300005;
priority_queue<int> pq;
vector<int> g[N];
int t,n,m,cnt[N],ans[N],sum;
void topo()
{
	sum=0;
	for(int i=1;i<=n;i++)
	{
		if(cnt[i]==0) pq.push(i);
	}
	while(!pq.empty())
	{
		int u=pq.top();
		pq.pop();
		ans[++sum]=u;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i];
			cnt[v]--;
			if(cnt[v]==0) pq.push(v);
		}
	}
	if(sum<n) cout<<"Impossible!\n";
	else
	{
		for(int i=n;i>0;i--) cout<<ans[i]<<" ";
		cout<<"\n";
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--)
	{
		cin>>n>>m;
		for(int i=1;i<=n;i++) g[i].clear();
		memset(cnt,0,sizeof(cnt));
		for(int i=1;i<=m;i++)
		{
			int x,y;
			cin>>x>>y;
			g[y].push_back(x);
			cnt[x]++;
		}
		topo();
	}
	return 0;
}
